code = """import json, pandas as pd, re

# Load books result (may be file path)
books_src = var_call_HQbqx9wvrGCNlR5H4PSLzDJf
if isinstance(books_src, str):
    with open(books_src, 'r', encoding='utf-8') as f:
        books = json.load(f)
else:
    books = books_src

reviews = var_call_Y4Ny7bZDlYzkOMVXFHGhgGba

bdf = pd.DataFrame(books)
rdf = pd.DataFrame(reviews)

# Extract numeric suffix for fuzzy join (bookid_123 <-> purchaseid_123)

def extract_num(s):
    if s is None:
        return None
    m = re.search(r'(\d+)$', str(s))
    return int(m.group(1)) if m else None

bdf['id_num'] = bdf['book_id'].map(extract_num)
rdf['id_num'] = rdf['purchase_id'].map(extract_num)

# Filter English-language via details containing 'English'
eng_mask = bdf['details'].fillna('').str.contains(r'\bEnglish\b', case=False, regex=True)

# Ensure category contains Literature & Fiction
cat_mask = bdf['categories'].fillna('').str.contains('Literature & Fiction', case=False, regex=False) | \
           bdf['details'].fillna('').str.contains('Literature & Fiction', case=False, regex=False)

bdf_f = bdf[eng_mask & cat_mask].copy()

# Join to perfect 5.0 avg
rdf['avg_rating'] = pd.to_numeric(rdf['avg_rating'])
rdf['review_count'] = pd.to_numeric(rdf['review_count'])

j = bdf_f.merge(rdf[rdf['avg_rating'] == 5.0], on='id_num', how='inner')

# Prepare output
out = j[['book_id','title','subtitle','author','avg_rating','review_count']].drop_duplicates().sort_values(['title','book_id'])

result = out.to_dict(orient='records')
print('__RESULT__:')
print(json.dumps(result, ensure_ascii=False))"""

